1	const countNeighbors = (grid: boolean[][], row: number, col: number): number => {
2	  let count = 0;
3	  for (let r = row - 1; r <= row + 1; r++) {
4	    for (let c = col - 1; c <= col + 1; c++) {
5	      if (r === row && c === col) continue;
6	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[r].length) {
7	        if (grid[r][c]) count++;
8	      }
9	    }
10	  }
11	  return count;
12	};
13	
14	const willBeAlive = (isAlive: boolean, neighborCount: number): boolean =>
15	  neighborCount === 3 || (isAlive && neighborCount === 2);
16	
17	export function nextGeneration(grid: boolean[][]): boolean[][] {
18	  if (grid.length === 1 && grid[0].length === 1) return [[]];
19	  return grid.map((row, rowIndex) =>
20	    row.map((cell, colIndex) =>
21	      willBeAlive(cell, countNeighbors(grid, rowIndex, colIndex))
22	    )
23	  );
24	}
